package org.mage.test.cards.single.mom;

import mage.constants.PhaseStep;
import mage.constants.Zone;
import org.junit.Test;
import org.mage.test.serverside.base.CardTestPlayerBase;

/**
 * @author TheElk801
 */
public class AyaraWidowOfTheRealmTest extends CardTestPlayerBase {

    private static final String ayara = "Ayara, Widow of the Realm";
    private static final String ayaraFurnaceQueen = "Ayara, Furnace Queen";

    /**
     * Test that Ayara, Furnace Queen can return an artifact or creature card from graveyard to battlefield.
     * Bug: The effect was not actually moving the card to the battlefield.
     */
    @Test
    public void testFurnaceQueenReturnFromGraveyard() {
        // Ayara, Furnace Queen directly on battlefield
        addCard(Zone.BATTLEFIELD, playerA, ayaraFurnaceQueen);
        // Noxious Gearhulk - artifact creature that can be targeted from graveyard
        addCard(Zone.GRAVEYARD, playerA, "Noxious Gearhulk");

        // At beginning of combat, Ayara, Furnace Queen triggers
        addTarget(playerA, "Noxious Gearhulk");

        setStopAt(1, PhaseStep.POSTCOMBAT_MAIN);
        execute();

        // Noxious Gearhulk should be on the battlefield
        assertPermanentCount(playerA, "Noxious Gearhulk", 1);
        assertGraveyardCount(playerA, "Noxious Gearhulk", 0);
    }

    /**
     * Test the full scenario: transform Ayara and then use the triggered ability.
     * This reproduces the reported bug where Ayara transforms and then fails to
     * return a creature that was sacrificed to her front-side ability.
     */
    @Test
    public void testFullTransformAndReturnScenario() {
        // Ayara, Widow of the Realm on battlefield
        addCard(Zone.BATTLEFIELD, playerA, ayara);
        // A creature to sacrifice: Noxious Gearhulk
        addCard(Zone.BATTLEFIELD, playerA, "Noxious Gearhulk");
        // Mana sources for transform cost: {5}{R/P}
        // Note: {R/P} can be paid with 2 life instead of red mana
        addCard(Zone.BATTLEFIELD, playerA, "Swamp", 5);

        // First, sacrifice Noxious Gearhulk to Ayara's tap ability
        // {T}, Sacrifice another creature or artifact: Ayara deals X damage to target opponent and you gain X life
        activateAbility(1, PhaseStep.PRECOMBAT_MAIN, playerA, "{T}, Sacrifice");
        addTarget(playerA, "Noxious Gearhulk"); // sacrifice target
        addTarget(playerA, playerB); // damage target (opponent)
        waitStackResolved(1, PhaseStep.PRECOMBAT_MAIN);

        // Noxious Gearhulk should now be in graveyard
        assertGraveyardCount(playerA, "Noxious Gearhulk", 1);

        // Now transform Ayara
        activateAbility(1, PhaseStep.PRECOMBAT_MAIN, playerA, "{5}{R/P}: Transform");
        setChoice(playerA, "Yes"); // pay 2 life for {R/P}
        waitStackResolved(1, PhaseStep.PRECOMBAT_MAIN);

        // At the beginning of combat, Ayara Furnace Queen triggers
        addTarget(playerA, "Noxious Gearhulk");

        setStopAt(1, PhaseStep.POSTCOMBAT_MAIN);
        execute();

        // Noxious Gearhulk should be returned to the battlefield
        assertPermanentCount(playerA, "Noxious Gearhulk", 1);
        assertGraveyardCount(playerA, "Noxious Gearhulk", 0);
    }
}

